from __future__ import annotations

import pytest

from psycopg import errors as e
from psycopg import sql
from psycopg.replication.replication_options import SnapshotOption


def check_logical_stream_health(conn, started_cur, table, timeout=0.5):
    started_cur.send_feedback(request_reply=True)

    started_cur.read_message(timeout=timeout)

    conn.execute("SELECT pg_logical_emit_message(false, 'test_psycopg', 'SUBSCRIBED')")

    started_cur.read_message(return_keepalive_messages=False, timeout=timeout)

    while True:
        try:
            started_cur.read_message(return_keepalive_messages=False, timeout=0.1)
        except e.ReadMessageTimeout:
            break

    conn.execute(f"INSERT INTO {table} (data) VALUES ('healthy?')")

    return started_cur.read_message(return_keepalive_messages=False, timeout=timeout)


def test_start_replication(conn, logical_conn, slot_name, test_table, publication):
    with logical_conn.cursor() as cur:
        cur.create_replication_slot(slot_name)
        cur.start_replication(
            slot_name, publication_names=publication, decoder=None, messages=True
        )
        check_logical_stream_health(conn, cur, test_table)


def test_start_replication_multiple_publications(
    conn,
    logical_conn,
    slot_name,
    test_table,
    publication,
    empty_publication,
    monkeypatch,
):
    with logical_conn.cursor() as cur:
        cur.create_replication_slot(slot_name)
        orig_execute = cur.execute
        statement: str

        def mock_execute(*args, **kwargs):
            nonlocal statement
            statement = sql.as_string(args[0])
            return orig_execute(*args, **kwargs)

        with monkeypatch.context() as m:
            m.setattr(cur, "execute", mock_execute)
            cur.start_replication(
                slot_name,
                publication_names=[empty_publication, publication],
                decoder=None,
                messages=True,
            )
        assert (
            f""""publication_names" '"{empty_publication}", "{publication}"'"""
            in statement
        )
        check_logical_stream_health(conn, cur, test_table)


