@pytest.mark.parametrize("option_value", [True, False])
@pytest.mark.parametrize(
    "option_name",
    [
        "include_xids",
        "include_timestamp",
        "force_binary",
        "skip_empty_xacts",
        "only_local",
        "include_rewrites",
        "stream_changes",
    ],
)
def test_start_replication_text_decoder(
    conn, logical_conn, slot_name, test_table, publication, option_name, option_value
):
    with logical_conn.cursor() as cur:
        cur.create_replication_slot(slot_name, output_plugin="test_decoding")
        cur.start_replication(slot_name, start_lsn="0/0", **{option_name: option_value})
        begin = check_logical_stream_health(conn, cur, test_table)
        insert = cur.read_message(timeout=1, return_keepalive_messages=False)
        commit = cur.read_message(timeout=1, return_keepalive_messages=False)

        for msg in (begin, insert, commit):
            assert isinstance(msg.payload, str)

        assert "INSERT" in insert.payload
        assert test_table in insert.payload
        assert "'healthy?'" in insert.payload

        if option_name == "include_xids" and option_value is False:
            assert "BEGIN" == begin.payload
            assert "COMMIT" == commit.payload
        else:
            assert "BEGIN " in begin.payload
            assert "COMMIT " in commit.payload


@pytest.mark.pg(">=15")
def test_create_slot_snapshot_use(logical_conn, slot_name):
    with logical_conn.transaction():
        with pytest.raises(e.InternalError_):
            with logical_conn.cursor() as cur:
                *_, snapshot_name, _ = cur.create_replication_slot(
                    slot_name, snapshot=SnapshotOption.USE
                )
    with logical_conn.transaction():
        # READ ONLY required on PostgreSQL 16+
        logical_conn.execute(
            "SET TRANSACTION ISOLATION LEVEL REPEATABLE READ, READ ONLY"
        )
        with logical_conn.cursor() as cur:
            *_, snapshot_name, _ = cur.create_replication_slot(
                slot_name, snapshot=SnapshotOption.USE
            )
    assert snapshot_name is None


@pytest.mark.pg(">=15")
def test_create_slot_snapshot_export(conn, logical_conn, slot_name):
    with logical_conn.cursor() as cur:
        *_, snapshot_name, _ = cur.create_replication_slot(
            slot_name, snapshot=SnapshotOption.EXPORT
        )
    assert snapshot_name is not None
    with conn.transaction():
        conn.execute("SET TRANSACTION ISOLATION LEVEL REPEATABLE READ")
        conn.execute(f"SET TRANSACTION SNAPSHOT '{snapshot_name}'")


