@pytest.mark.pg(">=17")
@pytest.mark.parametrize(
    "replication_slot_opts",
    [
        pytest.param(("failover",), id="failover", marks=[pytest.mark.pg("==17")]),
        pytest.param(
            ("failover", "two_phase"),
            id="two_phase-failover",
            marks=[pytest.mark.pg(">=18")],
        ),
    ],
)
def test_alter_replication_slot(logical_conn, slot_name, replication_slot_opts):

    def get_options(cur):
        cur.execute(
            f"SELECT {', '.join(replication_slot_opts)}"
            + " FROM pg_replication_slots WHERE slot_name = %s",
            [slot_name],
        )
        return cur.fetchone()

    with logical_conn.cursor() as cur:
        cur.create_replication_slot(
            slot_name, **{opt: False for opt in replication_slot_opts}
        )
        for option in get_options(cur):
            assert option is False
        cur.alter_replication_slot(
            slot_name, **{opt: True for opt in replication_slot_opts}
        )
        for option in get_options(cur):
            assert option is True


@pytest.mark.pg("<17")
def test_alter_replication_slot_raises(logical_conn, slot_name):
    with logical_conn.cursor() as cur:
        cur.create_replication_slot(slot_name, two_phase=False)
        with pytest.raises(ValueError, match="alter_replication_slot()"):
            cur.alter_replication_slot(slot_name, two_phase=True)
